#!/bin/sh
# cargo-loco-generate/cargo-loco-generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding orthopedic-assessment (6 tables)..."

cargo loco generate scaffold patient \
    deleted_at:ts \
    name:string! \
    birth_date:date \
    united_kingdom_nhs_number:string^ \
    waist_as_cm:double \
    height_as_cm:double \
    weight_as_kg:double \
    body_mass_index:double \
    waist_height_ratio:double \
    vo2_max:double \
    --htmx && \
cargo loco generate scaffold clinician \
    deleted_at:ts \
    name:text! \
    role:text! \
    registration_body:text! \
    registration_number:text! \
    united_kingdom_nhs_number:string^ \
    --htmx && \
cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    joint_assessed:string! \
    side_assessed:string! \
    overall_rom_status:string! \
    range_of_motion_notes:text! \
    range_of_motion:references \
    movement:string! \
    active_degrees:int \
    passive_degrees:int \
    normal_degrees:int \
    end_feel:string! \
    pain_on_movement:string! \
    sort_order:int! \
    grip_strength_affected_kg:double \
    grip_strength_unaffected_kg:double \
    overall_strength_status:string! \
    strength_testing_notes:text! \
    strength_testing:references \
    muscle_group:string! \
    strength_test_item_movement:string! \
    mrc_grade:int \
    pain_on_testing:string! \
    strength_test_item_sort_order:int! \
    has_previous_imaging:string! \
    imaging_requested:string! \
    imaging_requested_details:text! \
    imaging_notes:text! \
    imaging_history:references \
    modality:string! \
    body_region:string! \
    date_performed:date \
    findings:text! \
    imaging_item_sort_order:int! \
    has_previous_surgery:string! \
    surgery_considered:string! \
    surgery_considered_details:text! \
    patient_preference:string! \
    comorbidities_affecting_surgery:text! \
    anaesthetic_risk:string! \
    anticoagulant_use:string! \
    anticoagulant_details:text! \
    surgical_history_notes:text! \
    surgical_history:references \
    procedure_name:string! \
    surgery_item_date_performed:date \
    surgeon:string! \
    hospital:string! \
    outcome:string! \
    outcome_details:text! \
    surgery_item_sort_order:int! \
    --htmx && \
cargo loco generate scaffold grading_result \
    assessment:references \
    dash_score:double! \
    disability_category:string! \
    graded_at:ts! \
    --htmx && \
cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx && \
cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
